+// RealIPWithTrustedProxies returns a middleware that sets RemoteAddr to the
+// real client IP by walking the X-Forwarded-For chain from right to left and
+// selecting the first IP that is not within one of the supplied trusted proxy
+// CIDRs. trustedCIDRs is a list of CIDR strings (e.g. "10.0.0.0/8"). Any
+// CIDR that fails to parse is silently ignored. True-Client-IP and X-Real-IP
+// are still accepted as-is since those headers are not a chain.
+func RealIPWithTrustedProxies(trustedCIDRs []string) func(http.Handler) http.Handler {
+	var nets []*net.IPNet
+	for _, cidr := range trustedCIDRs {
+		_, ipNet, err := net.ParseCIDR(cidr)
+		if err == nil {
+			nets = append(nets, ipNet)
+		}
+	}
+
+	return func(h http.Handler) http.Handler {
+		fn := func(w http.ResponseWriter, r *http.Request) {
+			if rip := realIPFromTrusted(r, nets); rip != "" {
+				r.RemoteAddr = rip
+			}
+			h.ServeHTTP(w, r)
+		}
+		return http.HandlerFunc(fn)
+	}
+}
