+// realIPFromTrusted resolves the real client IP from r by walking the
+// X-Forwarded-For chain right-to-left and returning the first IP that does not
+// belong to any of the trusted proxy networks.
+func realIPFromTrusted(r *http.Request, trustedNets []*net.IPNet) string {
+	if tcip := r.Header.Get(trueClientIP); tcip != "" {
+		if ip := net.ParseIP(strings.TrimSpace(tcip)); ip != nil {
+			return ip.String()
+		}
+	}
+	if xrip := r.Header.Get(xRealIP); xrip != "" {
+		if ip := net.ParseIP(strings.TrimSpace(xrip)); ip != nil {
+			return ip.String()
+		}
+	}
+
+	xff := r.Header.Get(xForwardedFor)
+	if xff == "" {
+		return ""
+	}
+
+	parts := strings.Split(xff, ",")
+	for i := len(parts) - 1; i >= 0; i-- {
+		candidate := strings.TrimSpace(parts[i])
+		ip := net.ParseIP(candidate)
+		if ip == nil {
+			continue
+		}
+		if !isTrusted(ip, trustedNets) {
+			return ip.String()
+		}
+	}
+	return ""
+}
+
+func isTrusted(ip net.IP, nets []*net.IPNet) bool {
+	for _, n := range nets {
+		if n.Contains(ip) {
+			return true
+		}
+	}
+	return false
+}
